  const ::flatbuffers::Vector<::flatbuffers::Offset<::flatbuffers::String>> *SCHEMA_NAMES() const {
    return GetPointer<const ::flatbuffers::Vector<::flatbuffers::Offset<::flatbuffers::String>> *>(VT_SCHEMA_NAMES);
  }
