inline const DPM *GetDPM(const void *buf) {
  return ::flatbuffers::GetRoot<DPM>(buf);
}

inline const DPM *GetSizePrefixedDPM(const void *buf) {
  return ::flatbuffers::GetSizePrefixedRoot<DPM>(buf);
}

inline const char *DPMIdentifier() {
  return "$DPM";
}

inline bool DPMBufferHasIdentifier(const void *buf) {
  return ::flatbuffers::BufferHasIdentifier(
      buf, DPMIdentifier());
}

inline bool SizePrefixedDPMBufferHasIdentifier(const void *buf) {
  return ::flatbuffers::BufferHasIdentifier(
      buf, DPMIdentifier(), true);
}

template <bool B = false>
inline bool VerifyDPMBuffer(
    ::flatbuffers::VerifierTemplate<B> &verifier) {
  return verifier.template VerifyBuffer<DPM>(DPMIdentifier());
}

template <bool B = false>
inline bool VerifySizePrefixedDPMBuffer(
    ::flatbuffers::VerifierTemplate<B> &verifier) {
  return verifier.template VerifySizePrefixedBuffer<DPM>(DPMIdentifier());
}

inline void FinishDPMBuffer(
    ::flatbuffers::FlatBufferBuilder &fbb,
    ::flatbuffers::Offset<DPM> root) {
  fbb.Finish(root, DPMIdentifier());
}

inline void FinishSizePrefixedDPMBuffer(
    ::flatbuffers::FlatBufferBuilder &fbb,
    ::flatbuffers::Offset<DPM> root) {
  fbb.FinishSizePrefixed(root, DPMIdentifier());
}

